// ================================================
//  EDIT THIS NODE -- all your settings live here
// ================================================

var CLINIC_NAME     = 'Your Clinic Name';
var BOOKING_LINK    = 'YOUR_BOOKING_LINK';
var SLACK_CHANNEL   = 'YOUR_SLACK_CHANNEL_ID';
var LOG_SHEET_ID    = 'YOUR_LOG_SHEET_ID';
var LOG_SHEET_NAME  = 'Communications Log';

// ================================================
//  DO NOT EDIT BELOW THIS LINE
// ================================================

var form = $input.first().json;

var patientName   = form['Full Name'] || '';
var patientEmail  = form['Email Address'] || '';
var contactReason = form['Reason for Contact'] || '';
var lastVisit     = form['When was your last appointment?'] || 'not recorded';
var notes         = form['Additional notes (optional)'] || 'none';

return [{
  json: {
    clinic_name:    CLINIC_NAME,
    booking_link:   BOOKING_LINK,
    slack_channel:  SLACK_CHANNEL,
    log_sheet_id:   LOG_SHEET_ID,
    log_sheet_name: LOG_SHEET_NAME,
    patient_name:   patientName,
    patient_email:  patientEmail,
    contact_reason: contactReason,
    last_visit:     lastVisit,
    notes:          notes,
    timestamp:      new Date().toISOString()
  }
}];

var item = $input.first().json;
var rawText = item.text || '';
var parsed = {};

try {
  var match = rawText.match(/\{[\s\S]*\}/);
  if (match) parsed = JSON.parse(match[0]);
} catch (e) {
  parsed = {
    action: 'send_followup',
    urgency: 'normal',
    email_subject: 'Following up from our clinic',
    email_body: 'Thank you for being a valued patient. Please contact us if you need to book or change an appointment.',
    reason: 'AI parsing failed -- fallback message used'
  };
}

var validActions = ['send_welcome', 'rebook_appointment', 'send_followup'];
if (!validActions.includes(parsed.action)) parsed.action = 'send_followup';

return [{ json: Object.assign({}, item, {
  action:        parsed.action || 'send_followup',
  urgency:       parsed.urgency || 'normal',
  email_subject: parsed.email_subject || 'Message from our clinic',
  email_body:    parsed.email_body || '',
  reason:        parsed.reason || '',
  processed_at:  new Date().toISOString()
}) }];

var item = $input.first().json;
var msg = 'Re-booking email sent to patient\n' +
  'Patient: ' + (item.patient_name || 'unknown') + '\n' +
  'Email: ' + (item.patient_email || 'unknown') + '\n' +
  'Last visit: ' + (item.last_visit || 'unknown') + '\n' +
  'Reason for contact: ' + (item.contact_reason || 'unknown') + '\n' +
  'Claude reasoning: ' + (item.reason || 'n/a') + '\n' +
  'Please follow up to confirm a new appointment time.';
return [{ json: Object.assign({}, item, { slack_message: msg }) }];
